const WebSocket = require('ws');
const crypto = require('crypto');
const { v4: uuidv4 } = require('uuid');

const players = new Map();
const games = new Map();
const commandHistory = new Set();

class GameServer {
  constructor() {
    this.wss = new WebSocket.Server({ port: 8080 });
    this.setupWebSocketHandlers();
  }

  setupWebSocketHandlers() {
    this.wss.on('connection', (ws, req) => {
      const playerId = uuidv4();
      const gameKey = req.url.split('?game=')[1];
      
      if (!gameKey || !games.has(gameKey)) {
        ws.close(4001, 'Invalid game key');
        return;
      }

      const player = {
        id: playerId,
        ws: ws,
        gameKey: gameKey,
        lastCommandTime: 0,
        commandNonce: 0
      };

      players.set(playerId, player);
      ws.on('message', (message) => this.handleMessage(playerId, message));
      ws.on('close', () => this.handleDisconnect(playerId));
    });
  }

  handleMessage(playerId, message) {
    const player = players.get(playerId);
    if (!player) return;

    try {
      const data = JSON.parse(message);
      
      if (!this.validateCommand(data)) {
        player.ws.send(JSON.stringify({ error: 'Invalid command format' }));
        return;
      }

      const commandHash = this.generateCommandHash(data, player);
      
      if (commandHistory.has(commandHash)) {
        player.ws.send(JSON.stringify({ error: 'Command already processed' }));
        return;
      }

      commandHistory.add(commandHash);
      
      if (this.isCommandReplay(data, player)) {
        player.ws.send(JSON.stringify({ error: 'Replay attack detected' }));
        return;
      }

      this.processCommand(data, player);
      
    } catch (error) {
      player.ws.send(JSON.stringify({ error: 'Invalid message format' }));
    }
  }

  validateCommand(data) {
    if (!data || typeof data !== 'object') return false;
    
    const validTypes = ['build', 'attack', 'move'];
    if (!validTypes.includes(data.type)) return false;
    
    if (typeof data.playerId !== 'string' || data.playerId.length === 0) return false;
    
    if (data.type === 'build' && (!data.unitType || typeof data.unitType !== 'string')) return false;
    if (data.type === 'attack' && (!data.target || typeof data.target !== 'object')) return false;
    if (data.type === 'move' && (!data.target || typeof data.target !== 'object')) return false;
    
    return true;
  }

  generateCommandHash(data, player) {
    const commandString = JSON.stringify({
      type: data.type,
      playerId: data.playerId,
      nonce: data.nonce,
      timestamp: data.timestamp,
      payload: data.payload
    });
    
    return crypto.createHash('sha256').update(commandString).digest('hex');
  }

  isCommandReplay(data, player) {
    if (data.timestamp <= player.lastCommandTime) return true;
    return false;
  }

  processCommand(data, player) {
    const game = games.get(player.gameKey);
    if (!game) return;

    player.lastCommandTime = data.timestamp;
    player.commandNonce = data.nonce;

    switch (data.type) {
      case 'build':
        this.handleBuildCommand(data, player);
        break;
      case 'attack':
        this.handleAttackCommand(data, player);
        break;
      case 'move':
        this.handleMoveCommand(data, player);
        break;
    }
  }

  handleBuildCommand(data, player) {
    const game = games.get(player.gameKey);
    if (!game) return;

    const unit = {
      id: uuidv4(),
      type: data.unitType,
      x: data.payload?.x || 0,
      y: data.payload?.y || 0,
      health: 100,
      playerId: player.id
    };

    game.units.push(unit);
    this.broadcastToGame(player.gameKey, {
      type: 'unitBuilt',
      unit: unit
    });
  }

  handleAttackCommand(data, player) {
    const game = games.get(player.gameKey);
    if (!game) return;

    const targetUnit = game.units.find(u => u.id === data.target.id);
    if (!targetUnit) return;

    targetUnit.health -= 25;
    
    if (targetUnit.health <= 0) {
      game.units = game.units.filter(u => u.id !== targetUnit.id);
      this.broadcastToGame(player.gameKey, {
        type: 'unitDestroyed',
        unitId: targetUnit.id
      });
    } else {
      this.broadcastToGame(player.gameKey, {
        type: 'unitAttacked',
        unitId: targetUnit.id,
        health: targetUnit.health
      });
    }
  }

  handleMoveCommand(data, player) {
    const game = games.get(player.gameKey);
    if (!game) return;

    const unit = game.units.find(u => u.id === data.target.id);
    if (!unit) return;

    unit.x = data.payload?.x || unit.x;
    unit.y = data.payload?.y || unit.y;

    this.broadcastToGame(player.gameKey, {
      type: 'unitMoved',
      unitId: unit.id,
      x: unit.x,
      y: unit.y
    });
  }

  broadcastToGame(gameKey, message) {
    const game = games.get(gameKey);
    if (!game) return;

    const playersInGame = Array.from(players.values()).filter(p => p.gameKey === gameKey);
    playersInGame.forEach(player => {
      if (player.ws.readyState === WebSocket.OPEN) {
        player.ws.send(JSON.stringify(message));
      }
    });
  }

  handleDisconnect(playerId) {
    players.delete(playerId);
  }
}

const gameServer = new GameServer();

